  1	import React, { FC } from 'react';
  2	import * as _ from 'lodash';
  3	
  4	import { modelToGroupVersionKind, ServiceModel } from '@kubevirt-ui/kubevirt-api/console';
  5	import { IoK8sApiCoreV1Service } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
  6	import {
  7	  ResourceLink,
  8	  Timestamp,
  9	  useAccessReview,
 10	  useAnnotationsModal,
 11	  useLabelsModal,
 12	} from '@openshift-console/dynamic-plugin-sdk';
 13	import { Button, PageSection, Title } from '@patternfly/react-core';
 14	import { PencilAltIcon } from '@patternfly/react-icons';
 15	import { DetailsItem } from '@utils/components/DetailsItem/DetailsItem';
 16	import { LabelList } from '@utils/components/DetailsItem/LabelList';
 17	import Loading from '@utils/components/Loading/Loading';
 18	import { OwnerReferences } from '@utils/components/OwnerReference/owner-references';
 19	import { Selector } from '@utils/components/Selector/Selector';
 20	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 21	
 22	import ServiceAddress from './ServiceAddress';
 23	import ServicePortMapping from './ServicePortMapping';
 24	
 25	type DetailsProps = {
 26	  obj: IoK8sApiCoreV1Service;
 27	};
 28	
 29	const ServiceDetails: FC<DetailsProps> = ({ obj: service }) => {
 30	  const { t } = useNetworkingTranslation();
 31	  const metadata = service?.metadata;
 32	  const annotationsModalLauncher = useAnnotationsModal(service);
 33	  const labelsModalLauncher = useLabelsModal(service);
 34	
 35	  const [canUpdate] = useAccessReview({
 36	    group: ServiceModel?.apiGroup,
 37	    name: metadata?.name,
 38	    namespace: metadata?.namespace,
 39	    resource: ServiceModel?.plural,
 40	    verb: 'patch',
 41	  });
 42	
 43	  if (!service)
 44	    return (
 45	      <PageSection>
 46	        <Loading />
 47	      </PageSection>
 48	    );
 49	
 50	  return (
 51	    <>
 52	      <div className="co-m-pane__body">
 53	        <div className="row">
 54	          <div className="col-md-6">
 55	            <Title headingLevel="h2">{t('Service details')}</Title>
 56	            <dl className="co-m-pane__details" data-test-id="resource-summary">
 57	              <DetailsItem label={t('Name')} obj={service} path={'metadata.name'} />
 58	              {metadata?.namespace && (
 59	                <DetailsItem label={t('Namespace')} obj={service} path="metadata.namespace">
 60	                  <ResourceLink
 61	                    kind="Namespace"
 62	                    name={metadata?.namespace}
 63	                    namespace={null}
 64	                    title={metadata?.uid}
 65	                  />
 66	                </DetailsItem>
 67	              )}
 68	              <DetailsItem
 69	                canEdit={canUpdate}
 70	                editAsGroup
 71	                label={t('Labels')}
 72	                obj={service}
 73	                onEdit={labelsModalLauncher}
 74	                path="metadata.labels"
 75	                valueClassName="details-item__value--labels"
 76	              >
 77	                <LabelList
 78	                  groupVersionKind={modelToGroupVersionKind(ServiceModel)}
 79	                  labels={metadata?.labels}
 80	                />
 81	              </DetailsItem>
 82	
 83	              <DetailsItem label={t('Pod selector')} obj={service} path="spec.selector">
 84	                <Selector
 85	                  namespace={_.get(service, 'metadata.namespace')}
 86	                  selector={_.get(service, 'spec.selector')}
 87	                />
 88	              </DetailsItem>
 89	              <DetailsItem label={t('Annotations')} obj={service} path="metadata.annotations">
 90	                {canUpdate ? (
 91	                  <Button
 92	                    data-test="edit-annotations"
 93	                    isInline
 94	                    onClick={annotationsModalLauncher}
 95	                    type="button"
 96	                    variant="link"
 97	                  >
 98	                    {t('{{count}} annotation', {
 99	                      count: _.size(metadata?.annotations),
100	                    })}
101	                    <PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />
102	                  </Button>
103	                ) : (
104	                  t('{{count}} annotation', {
105	                    count: _.size(metadata?.annotations),
106	                  })
107	                )}
108	              </DetailsItem>
109	              <DetailsItem
110	                label={t('Session affinity')}
111	                obj={service}
112	                path="spec.sessionAffinity"
113	              />
114	              <DetailsItem label={t('Created at')} obj={service} path="metadata.creationTimestamp">
115	                <Timestamp timestamp={metadata?.creationTimestamp} />
116	              </DetailsItem>
117	              <DetailsItem label={t('Owner')} obj={service} path="metadata.ownerReferences">
118	                <OwnerReferences resource={service} />
119	              </DetailsItem>
120	            </dl>
121	          </div>
122	          <div className="col-md-6">
123	            <Title headingLevel="h2">{t('Service routing')}</Title>
124	            <dl>
125	              <dt>{t('Hostname')}</dt>
126	              <dd>
127	                <div className="co-select-to-copy">
128	                  {metadata?.name}.{metadata?.namespace}.svc.cluster.local
129	                </div>
130	                <div>{t('Accessible within the cluster only')}</div>
131	              </dd>
132	              <dt>{t('Service address')}</dt>
133	              <dd className="service-ips">
134	                <ServiceAddress service={service} />
135	              </dd>
136	              <DetailsItem label={t('Service port mapping')} obj={service} path="spec.ports">
137	                <div className="service-ips">
138	                  {service?.spec?.ports ? <ServicePortMapping ports={service.spec.ports} /> : '-'}
139	                </div>
140	              </DetailsItem>
141	            </dl>
142	          </div>
143	        </div>
144	      </div>
145	    </>
146	  );
147	};
148	
149	export default ServiceDetails;

